template:
{
  "schema": {
    "type": "object",
    "properties": {
      "disable_default_service_account_role_binding": {
        "type": "boolean",
        "title": "Disable Default Service Account Role Binding",
        "description": "Disable automatic binding of the default service account to any Role or ClusterRole"
      },
      "default_service_account_role": {
        "type": "string",
        "enum": [
          "view",
          "edit",
          "admin",
          "cluster-admin"
        ],
        "title": "Default Service Account Role",
        "description": "Role granted to the default service account when automatic binding is enabled"
      },
      "allow_cluster_role_bindings_in_namespace": {
        "type": "boolean",
        "title": "Allow ClusterRoleBindings in Namespace",
        "description": "Allow creation of ClusterRoleBindings that reference this namespace"
      },
      "rbac_default_role_unrestricted": {
        "type": "boolean",
        "title": "RBAC Default Role Unrestricted",
        "description": "Allow the default service account to have unrestricted access to the namespace"
      },
      "audit_rbac_changes": {
        "type": "boolean",
        "title": "Enable RBAC Audit Logging",
        "description": "Enable audit logging for all Role and RoleBinding modifications in this namespace"
      },
      "require_approved_rbac_changes": {
        "type": "boolean",
        "title": "Require Approval for RBAC Changes",
        "description": "Require manual approval for any Role or RoleBinding change requests in this namespace"
      },
      "max_role_binding_subjects": {
        "type": "integer",
        "minimum": 1,
        "maximum": 100,
        "title": "Max Subjects per RoleBinding",
        "description": "Maximum number of subjects allowed in a single RoleBinding"
      },
      "enforce_network_policies": {
        "type": "boolean",
        "title": "Enforce Network Policies",
        "description": "Enable enforcement of Kubernetes NetworkPolicies at the namespace level"
      },
      "default_network_policy_types": {
        "type": "array",
        "items": {
          "type": "string",
          "enum": [
            "Ingress",
            "Egress"
          ]
        },
        "title": "Default Network Policy Types",
        "description": "Default NetworkPolicy types applied when no explicit policies exist"
      },
      "allow_all_ingress_traffic": {
        "type": "boolean",
        "title": "Allow All Ingress Traffic",
        "description": "Allow all ingress traffic by default when no NetworkPolicy matches the pod"
      },
      "allow_all_egress_traffic": {
        "type": "boolean",
        "title": "Allow All Egress Traffic",
        "description": "Allow all egress traffic by default when no NetworkPolicy matches the pod"
      },
      "minimum_network_policies": {
        "type": "integer",
        "minimum": 1,
        "maximum": 100,
        "title": "Minimum Network Policies",
        "description": "Minimum number of NetworkPolicies required to mitigate traffic bypass"
      },
      "network_policy_namespace_allow_all_ingress": {
        "type": "boolean",
        "title": "Permissive Namespace Ingress",
        "description": "Allow all ingress traffic within the namespace via permissive NetworkPolicies"
      },
      "resource_quota_enforced": {
        "type": "boolean",
        "title": "Enforce Resource Quota",
        "description": "Enable enforcement of resource quotas in the namespace"
      },
      "limit_range_enforced": {
        "type": "boolean",
        "title": "Enforce LimitRange Defaults",
        "description": "Enable enforcement of LimitRange objects for default requests and limits"
      },
      "default_cpu_quota": {
        "type": "integer",
        "minimum": 0,
        "maximum": 1000000,
        "title": "Default CPU Quota (millicores)",
        "description": "Default maximum CPU allocation for the namespace"
      },
      "default_memory_quota": {
        "type": "integer",
        "minimum": 0,
        "maximum": 1048576,
        "title": "Default Memory Quota (Mi)",
        "description": "Default maximum memory allocation for the namespace"
      },
      "default_storage_quota": {
        "type": "integer",
        "minimum": 0,
        "maximum": 10000,
        "title": "Default Storage Quota (Gi)",
        "description": "Default maximum storage allocation for PersistentVolumeClaims in the namespace"
      },
      "max_pods_per_namespace": {
        "type": "integer",
        "minimum": 0,
        "maximum": 100000,
        "title": "Max Pods per Namespace",
        "description": "Maximum number of Pods allowed in the namespace"
      },
      "automount_service_account_token": {
        "type": "boolean",
        "title": "Automount Service Account Token",
        "description": "Enable automatic mounting of service account tokens into pods"
      },
      "projected_service_account_tokens": {
        "type": "boolean",
        "title": "Use Projected Service Account Tokens",
        "description": "Require usage of projected service account tokens (bound tokens) instead of legacy tokens"
      },
      "service_account_token_max_age": {
        "type": "integer",
        "minimum": 0,
        "maximum": 31536000,
        "title": "Service Account Token Max Age",
        "description": "Maximum age (in seconds) for service account tokens before expiration"
      },
      "pod_security_standard_level": {
        "type": "string",
        "enum": [
          "privileged",
          "baseline",
          "restricted"
        ],
        "title": "Pod Security Standard Level",
        "description": "Pod Security admission level enforced for the namespace"
      },
      "admission_controllers": {
        "type": "array",
        "items": {
          "type": "string"
        },
        "title": "Admission Controllers",
        "description": "List of admission controllers enabled in the Kubernetes API server"
      },
      "enable_pod_security_policies": {
        "type": "boolean",
        "title": "Enable PodSecurityPolicy",
        "description": "Flag to enable PodSecurityPolicy admission controller"
      },
      "gatekeeper_policy_enforcement_mode": {
        "type": "string",
        "enum": [
          "enforce",
          "audit",
          "off"
        ],
        "title": "Gatekeeper Enforcement Mode",
        "description": "OPA Gatekeeper policy enforcement mode"
      },
      "privileged_containers_allowed": {
        "type": "boolean",
        "title": "Allow Privileged Containers",
        "description": "Whether containers can be run with privilege escalation or SYS_ADMIN capabilities"
      },
      "host_path_mounts_allowed": {
        "type": "boolean",
        "title": "Allow HostPath Mounts",
        "description": "Whether pods are allowed to mount hostPath volumes"
      },
      "required_namespace_label_key": {
        "type": "string",
        "title": "Required Namespace Label Key",
        "description": "Label key that must be present on all namespaces to apply network and RBAC policies"
      },
      "required_namespace_label_value": {
        "type": "string",
        "title": "Required Namespace Label Value",
        "description": "Expected value for the required namespace label key"
      },
      "require_rbac_label_selector": {
        "type": "boolean",
        "title": "Require RBAC Label Selector",
        "description": "Require RBAC RoleBindings to include namespace label selectors for scoping"
      },
      "rbac_selector_labels": {
        "type": "array",
        "items": {
          "type": "string"
        },
        "title": "RBAC Selector Labels",
        "description": "List of namespace label keys allowed for RBAC RoleBinding selectors"
      },
      "enable_api_audit_logging": {
        "type": "boolean",
        "title": "Enable API Audit Logging",
        "description": "Enable Kubernetes API server audit logging for service account token usage"
      }
    },
    "required": [
      "disable_default_service_account_role_binding",
      "default_service_account_role",
      "allow_cluster_role_bindings_in_namespace",
      "require_approved_rbac_changes",
      "enforce_network_policies",
      "resource_quota_enforced",
      "automount_service_account_token",
      "projected_service_account_tokens",
      "admission_controllers",
      "enable_pod_security_policies",
      "gatekeeper_policy_enforcement_mode",
      "privileged_containers_allowed",
      "rbac_default_role_unrestricted",
      "audit_rbac_changes",
      "service_account_token_max_age",
      "pod_security_standard_level",
      "network_policy_namespace_allow_all_ingress",
      "required_namespace_label_key",
      "require_rbac_label_selector"
    ]
  },
  "uischema": {
    "type": "Categorization",
    "elements": [
      {
        "type": "Category",
        "label": "Service Account & RBAC Basics",
        "elements": [
          {
            "type": "HorizontalLayout",
            "elements": [
              {
                "type": "Control",
                "scope": "#/properties/disable_default_service_account_role_binding"
              },
              {
                "type": "Control",
                "scope": "#/properties/default_service_account_role",
                "rule": {
                  "effect": "SHOW",
                  "condition": {
                    "scope": "#/properties/disable_default_service_account_role_binding",
                    "schema": {
                      "const": false
                    }
                  }
                }
              }
            ]
          },
          {
            "type": "HorizontalLayout",
            "elements": [
              {
                "type": "Control",
                "scope": "#/properties/allow_cluster_role_bindings_in_namespace"
              },
              {
                "type": "Control",
                "scope": "#/properties/rbac_default_role_unrestricted"
              }
            ]
          }
        ]
      },
      {
        "type": "Category",
        "label": "RBAC Auditing & Constraints",
        "elements": [
          {
            "type": "HorizontalLayout",
            "elements": [
              {
                "type": "Control",
                "scope": "#/properties/audit_rbac_changes"
              },
              {
                "type": "Control",
                "scope": "#/properties/require_approved_rbac_changes",
                "rule": {
                  "effect": "SHOW",
                  "condition": {
                    "scope": "#/properties/audit_rbac_changes",
                    "schema": {
                      "const": true
                    }
                  }
                }
              }
            ]
          },
          {
            "type": "HorizontalLayout",
            "elements": [
              {
                "type": "Control",
                "scope": "#/properties/max_role_binding_subjects"
              },
              {
                "type": "Control",
                "scope": "#/properties/require_rbac_label_selector"
              }
            ]
          },
          {
            "type": "HorizontalLayout",
            "elements": [
              {
                "type": "Control",
                "scope": "#/properties/rbac_selector_labels",
                "rule": {
                  "effect": "SHOW",
                  "condition": {
                    "scope": "#/properties/require_rbac_label_selector",
                    "schema": {
                      "const": true
                    }
                  }
                }
              }
            ]
          }
        ]
      },
      {
        "type": "Category",
        "label": "Network Policies",
        "elements": [
          {
            "type": "HorizontalLayout",
            "elements": [
              {
                "type": "Control",
                "scope": "#/properties/enforce_network_policies"
              },
              {
                "type": "Control",
                "scope": "#/properties/default_network_policy_types",
                "rule": {
                  "effect": "SHOW",
                  "condition": {
                    "scope": "#/properties/enforce_network_policies",
                    "schema": {
                      "const": true
                    }
                  }
                }
              }
            ]
          },
          {
            "type": "HorizontalLayout",
            "elements": [
              {
                "type": "Control",
                "scope": "#/properties/allow_all_ingress_traffic",
                "rule": {
                  "effect": "SHOW",
                  "condition": {
                    "scope": "#/properties/enforce_network_policies",
                    "schema": {
                      "const": true
                    }
                  }
                }
              },
              {
                "type": "Control",
                "scope": "#/properties/allow_all_egress_traffic",
                "rule": {
                  "effect": "SHOW",
                  "condition": {
                    "scope": "#/properties/enforce_network_policies",
                    "schema": {
                      "const": true
                    }
                  }
                }
              }
            ]
          },
          {
            "type": "HorizontalLayout",
            "elements": [
              {
                "type": "Control",
                "scope": "#/properties/minimum_network_policies",
                "rule": {
                  "effect": "SHOW",
                  "condition": {
                    "scope": "#/properties/enforce_network_policies",
                    "schema": {
                      "const": true
                    }
                  }
                }
              },
              {
                "type": "Control",
                "scope": "#/properties/network_policy_namespace_allow_all_ingress"
              }
            ]
          }
        ]
      },
      {
        "type": "Category",
        "label": "Resource Quotas & Limits",
        "elements": [
          {
            "type": "HorizontalLayout",
            "elements": [
              {
                "type": "Control",
                "scope": "#/properties/resource_quota_enforced"
              },
              {
                "type": "Control",
                "scope": "#/properties/limit_range_enforced",
                "rule": {
                  "effect": "SHOW",
                  "condition": {
                    "scope": "#/properties/resource_quota_enforced",
                    "schema": {
                      "const": true
                    }
                  }
                }
              }
            ]
          },
          {
            "type": "HorizontalLayout",
            "elements": [
              {
                "type": "Control",
                "scope": "#/properties/default_cpu_quota",
                "rule": {
                  "effect": "SHOW",
                  "condition": {
                    "scope": "#/properties/resource_quota_enforced",
                    "schema": {
                      "const": true
                    }
                  }
                }
              },
              {
                "type": "Control",
                "scope": "#/properties/default_memory_quota",
                "rule": {
                  "effect": "SHOW",
                  "condition": {
                    "scope": "#/properties/resource_quota_enforced",
                    "schema": {
                      "const": true
                    }
                  }
                }
              }
            ]
          },
          {
            "type": "HorizontalLayout",
            "elements": [
              {
                "type": "Control",
                "scope": "#/properties/default_storage_quota",
                "rule": {
                  "effect": "SHOW",
                  "condition": {
                    "scope": "#/properties/resource_quota_enforced",
                    "schema": {
                      "const": true
                    }
                  }
                }
              },
              {
                "type": "Control",
                "scope": "#/properties/max_pods_per_namespace",
                "rule": {
                  "effect": "SHOW",
                  "condition": {
                    "scope": "#/properties/resource_quota_enforced",
                    "schema": {
                      "const": true
                    }
                  }
                }
              }
            ]
          }
        ]
      },
      {
        "type": "Category",
        "label": "Service Account Tokens",
        "elements": [
          {
            "type": "HorizontalLayout",
            "elements": [
              {
                "type": "Control",
                "scope": "#/properties/automount_service_account_token"
              },
              {
                "type": "Control",
                "scope": "#/properties/projected_service_account_tokens",
                "rule": {
                  "effect": "SHOW",
                  "condition": {
                    "scope": "#/properties/automount_service_account_token",
                    "schema": {
                      "const": true
                    }
                  }
                }
              }
            ]
          },
          {
            "type": "HorizontalLayout",
            "elements": [
              {
                "type": "Control",
                "scope": "#/properties/service_account_token_max_age"
              },
              {
                "type": "Control",
                "scope": "#/properties/enable_api_audit_logging"
              }
            ]
          }
        ]
      },
      {
        "type": "Category",
        "label": "Admission & Security Policies",
        "elements": [
          {
            "type": "HorizontalLayout",
            "elements": [
              {
                "type": "Control",
                "scope": "#/properties/admission_controllers"
              },
              {
                "type": "Control",
                "scope": "#/properties/enable_pod_security_policies"
              }
            ]
          },
          {
            "type": "HorizontalLayout",
            "elements": [
              {
                "type": "Control",
                "scope": "#/properties/gatekeeper_policy_enforcement_mode"
              },
              {
                "type": "Control",
                "scope": "#/properties/pod_security_standard_level"
              }
            ]
          },
          {
            "type": "HorizontalLayout",
            "elements": [
              {
                "type": "Control",
                "scope": "#/properties/privileged_containers_allowed",
                "rule": {
                  "effect": "SHOW",
                  "condition": {
                    "scope": "#/properties/enable_pod_security_policies",
                    "schema": {
                      "const": true
                    }
                  }
                }
              },
              {
                "type": "Control",
                "scope": "#/properties/host_path_mounts_allowed",
                "rule": {
                  "effect": "SHOW",
                  "condition": {
                    "scope": "#/properties/enable_pod_security_policies",
                    "schema": {
                      "const": true
                    }
                  }
                }
              }
            ]
          }
        ]
      },
      {
        "type": "Category",
        "label": "Namespace Labels Enforcement",
        "elements": [
          {
            "type": "HorizontalLayout",
            "elements": [
              {
                "type": "Control",
                "scope": "#/properties/required_namespace_label_key"
              },
              {
                "type": "Control",
                "scope": "#/properties/required_namespace_label_value",
                "rule": {
                  "effect": "SHOW",
                  "condition": {
                    "scope": "#/properties/required_namespace_label_key",
                    "schema": {
                      "minLength": 1
                    }
                  }
                }
              }
            ]
          }
        ]
      }
    ]
  }
}

{
  "schema": {
    "type": "object",
    "properties": {
      "enforce_two_factor_for_organization": {
        "type": "boolean",
        "title": "Require 2FA for Organization Members",
        "description": "Mandate two-factor authentication for all organization members to strengthen account security."
      },
      "enforce_two_factor_authentication": {
        "type": "boolean",
        "title": "Enable Two-Factor Authentication",
        "description": "Require users to enroll in two-factor authentication for additional login protection."
      },
      "require_saml_sso": {
        "type": "boolean",
        "title": "Require SAML Single Sign-On",
        "description": "Force all authentication flows to use SAML SSO for centralized identity management."
      },
      "enforce_mfa_for_write_access": {
        "type": "boolean",
        "title": "MFA for Write/Admin Access",
        "description": "Require multi-factor authentication for any user with write or administrative repository privileges."
      },
      "failed_login_attempts_lockout_threshold": {
        "type": "integer",
        "minimum": 0,
        "maximum": 10,
        "title": "Failed Login Lockout Threshold",
        "description": "Number of consecutive failed sign-in attempts before the account is automatically locked."
      },
      "password_min_length": {
        "type": "integer",
        "minimum": 8,
        "maximum": 128,
        "title": "Minimum Password Length",
        "description": "Set the minimum number of characters required for user passwords."
      },
      "password_complexity_level": {
        "type": "string",
        "enum": [
          "low",
          "medium",
          "high"
        ],
        "title": "Password Complexity Level",
        "description": "Define complexity requirements (character classes) for user passwords."
      },
      "outside_collaborators_permissions": {
        "type": "string",
        "enum": [
          "read",
          "triage",
          "write",
          "maintain",
          "admin"
        ],
        "title": "Permissions for Outside Collaborators",
        "description": "Specify the level of repository access granted to outside collaborators."
      },
      "restrict_login_ips": {
        "type": "boolean",
        "title": "Restrict Login by IP",
        "description": "Limit user logins to a defined set of IP addresses or CIDR ranges."
      },
      "allowed_login_ip_addresses": {
        "type": "array",
        "items": {
          "type": "string"
        },
        "title": "Allowed Login IP Addresses",
        "description": "List of IP addresses or CIDR ranges permitted for user logins."
      },
      "api_rate_limiting_enabled": {
        "type": "boolean",
        "title": "Enable API Rate Limiting",
        "description": "Throttle API requests per client to prevent abuse and ensure service availability."
      },
      "api_rate_limit_threshold": {
        "type": "integer",
        "minimum": 1,
        "maximum": 10000,
        "title": "API Rate Limit (per minute)",
        "description": "Maximum number of API requests permitted per client each minute."
      },
      "api_rate_limit_burst_limit": {
        "type": "integer",
        "minimum": 1,
        "maximum": 1000,
        "title": "API Burst Limit",
        "description": "Allowed burst of API requests in a short window before sustained rate limiting applies."
      },
      "api_authentication_required": {
        "type": "boolean",
        "title": "Require API Authentication",
        "description": "Force authentication on all public and private API endpoints."
      },
      "api_ip_whitelist": {
        "type": "array",
        "items": {
          "type": "string"
        },
        "title": "API IP Whitelist",
        "description": "Define IP addresses or CIDR ranges allowed to access the API."
      },
      "api_access_logging_enabled": {
        "type": "boolean",
        "title": "Enable API Access Logging",
        "description": "Record detailed logs of all API requests for monitoring and forensics."
      },
      "branch_protection_enabled": {
        "type": "boolean",
        "title": "Enable Branch Protection",
        "description": "Prevent direct pushes and enforce merge restrictions on the default branch."
      },
      "require_pull_request_reviews": {
        "type": "boolean",
        "title": "Require Pull Request Reviews",
        "description": "Mandate one or more code reviews before merging changes into protected branches."
      },
      "branch_protection_required_reviews": {
        "type": "integer",
        "minimum": 1,
        "maximum": 10,
        "title": "Minimum PR Reviews",
        "description": "Specify the minimum number of reviewer approvals required for merges."
      },
      "enforce_code_owners_review": {
        "type": "boolean",
        "title": "Enforce Code Owners Review",
        "description": "Require designated code owners to approve changes to critical paths."
      },
      "allow_force_push": {
        "type": "boolean",
        "title": "Allow Force Push",
        "description": "Permit force pushes on protected branches (use with caution)."
      },
      "signature_verification_mandate": {
        "type": "boolean",
        "title": "Require Signed Commits & Tags",
        "description": "Enforce GPG or SSH-signed commits and tags for source integrity."
      },
      "restrict_workflow_modify": {
        "type": "boolean",
        "title": "Restrict Workflow File Modifications",
        "description": "Limit who can create or change GitHub Actions workflow files."
      },
      "enforce_workflow_approval": {
        "type": "boolean",
        "title": "Require Workflow Approval",
        "description": "Mandate explicit approval before workflows can be modified or executed."
      },
      "allowed_actions_policy": {
        "type": "string",
        "enum": [
          "all",
          "local",
          "selected"
        ],
        "title": "Allowed Actions Policy",
        "description": "Restrict which GitHub Actions workflows may run: all public, only local, or selected."
      },
      "approved_actions": {
        "type": "array",
        "items": {
          "type": "string"
        },
        "title": "Approved Actions List",
        "description": "List specific external actions that are permitted when using a 'selected' policy."
      },
      "restrict_third_party_actions": {
        "type": "boolean",
        "title": "Block Third-Party Actions",
        "description": "Prevent workflows from running actions defined in external repositories."
      },
      "default_workflow_permissions": {
        "type": "string",
        "enum": [
          "read-all",
          "write-all",
          "least-privilege"
        ],
        "title": "Default Workflow Permissions",
        "description": "Set the baseline permissions for the GITHUB_TOKEN in all workflows."
      },
      "secret_scanning_enabled": {
        "type": "boolean",
        "title": "Enable Secret Scanning",
        "description": "Automatically scan repositories for accidentally committed credentials."
      },
      "require_secret_scanning_before_merge": {
        "type": "boolean",
        "title": "Require Secret Scan before Merge",
        "description": "Block pull request merges until secret scanning passes without findings."
      },
      "fail_ci_scan_on_secret_detection": {
        "type": "boolean",
        "title": "Fail CI on Secret Detection",
        "description": "Automatically fail CI/CD pipelines when secret scanning uncovers exposed tokens."
      },
      "require_encrypted_secrets_in_actions": {
        "type": "boolean",
        "title": "Encrypt Action Secrets",
        "description": "Enforce encryption for all secrets stored in GitHub Actions workflows."
      },
      "restrict_token_scopes": {
        "type": "boolean",
        "title": "Restrict Token Scopes",
        "description": "Limit personal access tokens to the minimum required privileges."
      },
      "token_expiration_days": {
        "type": "integer",
        "minimum": 1,
        "maximum": 365,
        "title": "Token Expiration (Days)",
        "description": "Define how many days before personal access and OAuth tokens expire."
      },
      "required_secret_scanning": {
        "type": "boolean",
        "title": "Enforce Secret Scanning on Public Repos",
        "description": "Automatically scan public repositories for secrets on every commit."
      },
      "dependency_review_enabled": {
        "type": "boolean",
        "title": "Enable Dependency Review",
        "description": "Flag insecure or unreviewed dependencies in pull requests."
      },
      "dependabot_security_updates": {
        "type": "boolean",
        "title": "Enable Dependabot Security Updates",
        "description": "Automatically open pull requests to fix flagged vulnerabilities."
      },
      "allowed_packages_sources": {
        "type": "array",
        "items": {
          "type": "string"
        },
        "title": "Allowed Package Sources",
        "description": "List approved registry URLs or scopes for project dependencies."
      },
      "lockfile_enforcement": {
        "type": "boolean",
        "title": "Require Dependency Lockfile",
        "description": "Enforce use of a lockfile (e.g., package-lock.json) for reproducible builds."
      },
      "default_repository_visibility": {
        "type": "string",
        "enum": [
          "public",
          "internal",
          "private"
        ],
        "title": "Default Repository Visibility",
        "description": "Set the default visibility for newly created repositories."
      },
      "allow_public_repositories": {
        "type": "boolean",
        "title": "Allow Public Repos",
        "description": "Permit users to create or change repositories to public visibility."
      },
      "require_repository_approval": {
        "type": "boolean",
        "title": "Require Approval for Public Repos",
        "description": "Require an administrator to approve before a repository becomes public."
      },
      "allowed_public_repository_patterns": {
        "type": "array",
        "items": {
          "type": "string"
        },
        "title": "Public Repo Name Patterns",
        "description": "Regex patterns that public repository names must match."
      },
      "allow_forking": {
        "type": "boolean",
        "title": "Allow Forking",
        "description": "Enable repository forking by any user."
      },
      "repository_visibility": {
        "type": "string",
        "enum": [
          "public",
          "internal",
          "private"
        ],
        "title": "Repository Visibility",
        "description": "Override visibility setting for this repository."
      }
    },
    "required": [
      "branch_protection_enabled",
      "require_pull_request_reviews",
      "enforce_two_factor_authentication",
      "require_saml_sso",
      "failed_login_attempts_lockout_threshold",
      "secret_scanning_enabled",
      "require_secret_scanning_before_merge",
      "fail_ci_scan_on_secret_detection",
      "restrict_token_scopes",
      "dependency_review_enabled",
      "dependabot_security_updates",
      "allowed_actions_policy",
      "restrict_third_party_actions",
      "pull_request_fork_protection",
      "api_rate_limiting_enabled",
      "api_authentication_required",
      "default_repository_visibility",
      "allow_public_repositories",
      "repository_visibility",
      "enforce_two_factor_for_organization"
    ]
  },
  "uischema": {
    "type": "Categorization",
    "elements": [
      {
        "type": "Category",
