                "type": "Control",
                "scope": "#/properties/api_rate_limit_burst_limit"
              },
              {
                "type": "Control",
                "scope": "#/properties/api_authentication_required"
              }
            ]
          },
          {
            "type": "HorizontalLayout",
            "elements": [
              {
                "type": "Control",
                "scope": "#/properties/api_ip_whitelist"
              },
              {
                "type": "Control",
                "scope": "#/properties/api_access_logging_enabled"
              }
            ]
          }
        ]
      },
      {
        "type": "Category",
