              {
                "type": "Control",
                "scope": "#/properties/branch_protection_enabled"
              },
              {
                "type": "Control",
                "scope": "#/properties/require_pull_request_reviews",
                "rule": {
                  "effect": "SHOW",
                  "condition": {
                    "scope": "#/properties/branch_protection_enabled",
                    "schema": {
                      "const": true
                    }
                  }
                }
              }
            ]
          },
          {
            "type": "HorizontalLayout",
            "elements": [
              {
                "type": "Control",
                "scope": "#/properties/branch_protection_required_reviews"
              },
              {
                "type": "Control",
                "scope": "#/properties/enforce_code_owners_review",
                "rule": {
                  "effect": "SHOW",
                  "condition": {
                    "scope": "#/properties/branch_protection_enabled",
                    "schema": {
                      "const": true
                    }
                  }
                }
              }
            ]
          },
          {
            "type": "HorizontalLayout",
            "elements": [
              {
                "type": "Control",
                "scope": "#/properties/allow_force_push",
                "rule": {
                  "effect": "SHOW",
                  "condition": {
                    "scope": "#/properties/branch_protection_enabled",
                    "schema": {
                      "const": true
                    }
                  }
                }
              },
              {
                "type": "Control",
                "scope": "#/properties/signature_verification_mandate"
              }
            ]
          }
        ]
      },
      {
        "type": "Category",
        "label": "Workflow & Actions",
        "elements": [
          {
            "type": "HorizontalLayout",
