              },
              {
                "type": "Control",
                "scope": "#/properties/approved_actions",
                "rule": {
                  "effect": "SHOW",
                  "condition": {
                    "scope": "#/properties/allowed_actions_policy",
                    "schema": {
                      "const": "selected"
                    }
                  }
                }
              }
            ]
          },
          {
            "type": "HorizontalLayout",
            "elements": [
              {
                "type": "Control",
                "scope": "#/properties/restrict_third_party_actions"
              },
              {
                "type": "Control",
                "scope": "#/properties/default_workflow_permissions"
              }
            ]
          }
        ]
      },
      {
        "type": "Category",
        "label": "Secrets & Scanning",
        "elements": [
