                "rule": {
                  "effect": "SHOW",
                  "condition": {
                    "scope": "#/properties/allow_public_repositories",
                    "schema": {
                      "const": true
                    }
                  }
                }
              }
            ]
          }
        ]
      },
      {
        "type": "Category",
        "label": "Dependency & Package Management",
        "elements": [
          {
            "type": "HorizontalLayout",
            "elements": [
              {
                "type": "Control",
                "scope": "#/properties/dependency_review_enabled"
              },
              {
                "type": "Control",
                "scope": "#/properties/dependabot_security_updates",
                "rule": {
                  "effect": "SHOW",
                  "condition": {
                    "scope": "#/properties/dependency_review_enabled",
                    "schema": {
                      "const": true
                    }
                  }
                }
              }
            ]
          },
          {
            "type": "HorizontalLayout",
            "elements": [
              {
                "type": "Control",
                "scope": "#/properties/allowed_packages_sources"
              },
              {
                "type": "Control",
                "scope": "#/properties/lockfile_enforcement"
